function showPrintLoading() {
	if (document.getElementById('myd-print-loading')) return;
	var overlay = document.createElement('div');
	overlay.id = 'myd-print-loading';
	overlay.style.position = 'fixed';
	overlay.style.top = 0;
	overlay.style.left = 0;
	overlay.style.width = '100vw';
	overlay.style.height = '100vh';
	overlay.style.background = 'rgba(255,255,255,0.85)';
	overlay.style.zIndex = 2147483647;
	overlay.style.display = 'flex';
	overlay.style.alignItems = 'center';
	overlay.style.justifyContent = 'center';
	overlay.style.pointerEvents = 'all';
	overlay.innerHTML = '<div style="padding:32px 48px;background:#fff;border-radius:12px;box-shadow:0 2px 16px #0002;font-size:1.3em;font-weight:bold;display:flex;align-items:center;gap:16px;color:#222;"><span style="width:32px;height:32px;border:4px solid #ccc;border-top:4px solid #333;border-radius:50%;display:inline-block;animation:mydspin 1s linear infinite;"></span>Imprimindo...</div>';
	document.body.appendChild(overlay);
	var style = document.createElement('style');
	style.innerHTML = '@keyframes mydspin{0%{transform:rotate(0deg);}100%{transform:rotate(360deg);}}';
	document.head.appendChild(style);
}
function hidePrintLoading() {
	var overlay = document.getElementById('myd-print-loading');
	if (overlay) overlay.remove();
}
/*
 * Orders panel: ensure socket.io is available, request anonymous token and
 * connect to push server. This is a lightweight fallback connector for setups
 * where the inline panel script is not executed or when the panel is loaded
 * via an external asset bundle.
 */
(function () {
	function ensureSocketIo(cb) {
		if (typeof io !== 'undefined') return cb();
		try {
			var s = document.createElement('script');
			s.src = 'https://cdn.socket.io/4.7.2/socket.io.min.js';
			s.async = true;
			s.onload = function () { setTimeout(cb, 0); };
			s.onerror = function () { console.error('[Orders Panel][frontend.min] failed to load socket.io CDN'); cb(); };
			document.head.appendChild(s);
		} catch (e) { console.error(e); cb(); }
	}

	function fetchTokenAndConnect(pushUrl, restBase) {
		if (!pushUrl) { console.warn('[Orders Panel][frontend.min] pushUrl vazio - configure myd_push_server_url'); return; }
		// Guard redundante: verificar se o panel.php já registrou o socket
		// (pode ter sido definido após o DOMContentLoaded mas antes deste fetch retornar)
		if (window._mydPanelSocketRegistered || window.mydPushSocket) {
			console.log('[Orders Panel][frontend.min] panel.php socket detectado — fallback abortado');
			return;
		}
		var authUrl = (restBase || '/wp-json/myd-delivery/v1/') + 'push/auth';
		try {
			var headers = { 'Content-Type': 'application/json' };
			if (window.wpApiSettings && window.wpApiSettings.nonce) {
				headers['X-WP-Nonce'] = window.wpApiSettings.nonce;
			} else if (window.order_ajax_object && window.order_ajax_object.nonce) {
				headers['X-WP-Nonce'] = window.order_ajax_object.nonce;
			}
			fetch(authUrl, {
				method: 'POST',
				headers: headers,
				body: JSON.stringify({ myd_customer_id: 0 }),
				credentials: 'same-origin'
			}).then(function (r) { return r.json(); }).then(function (data) {
				if (data && data.token) {
					try {
						var socket = io(pushUrl, { auth: { token: data.token } });
						try { window.mydPushSocket = socket; } catch (_) { }
						console.log('[Orders Panel][frontend.min] socket connected (fallback)', socket && socket.id);
						socket.on('order.status', function (payload) {
							try { console.log('[Orders Panel][frontend.min] order.status', payload); } catch (_) { }
							// re-dispatch a DOM event so other scripts can listen
							try { document.dispatchEvent(new CustomEvent('myd:order.status', { detail: payload })); } catch (e) { }
							// Mirror minimal UI update logic if orders panel markup exists on page
							try {
								if (!payload || !payload.order_id) return;
								var id = String(payload.order_id);
								var rawStatus = (payload.status || payload.order_status || '');
								function normalizeStatus(s) {
									if (!s) return 'new';
									s = String(s).toLowerCase().trim();
									s = s.replace(/[_\s]+/g, '-');
									if (['created', 'received', 'pending'].indexOf(s) !== -1) return 'new';
									if (['processing', 'preparing', 'accepted', 'accept', 'accepted-order', 'preparando', 'confirmado', 'ready-for-preparation', 'ready'].indexOf(s) !== -1) return 'confirmed';
									if (['in-delivery', 'indelivery', 'out-for-delivery', 'out-for-shipping', 'despachado'].indexOf(s) !== -1) return 'in-delivery';
									if (s === 'finished' || s === 'completed') return 'done';
									return s;
								}
								var status = normalizeStatus(rawStatus);
								var item = null;
								try { item = document.querySelector('.fdm-orders-items#' + CSS.escape(id)); } catch (_) { item = null; }
								if (!item) {
									// try common alternative ids (with prefix)
									try { item = document.querySelector('.fdm-orders-items#order-' + CSS.escape(id)); } catch (_) { item = null; }
								}
								if (!item) return void (function () {
									// Card não existe no DOM — buscar via AJAX e inserir
									try {
										// Guard: evita corrida com polling (à mesma hora, um Set global sinaliza que este ID está sendo processado)
										if (!window.__mydInsertingIds) window.__mydInsertingIds = new Set();
										if (window.__mydInsertingIds.has(id)) {
											console.log('[Orders Panel][frontend.min] Card #' + id + ' já sendo inserido — pulando (dedup)');
											return;
										}
										window.__mydInsertingIds.add(id);
										if (window.order_ajax_object && window.order_ajax_object.ajax_url && window.order_ajax_object.nonce) {
											fetch(window.order_ajax_object.ajax_url, {
												method: 'POST', credentials: 'same-origin',
												headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Cache-Control': 'no-cache' },
												body: 'action=update_orders&nonce=' + encodeURIComponent(window.order_ajax_object.nonce)
											}).then(function (r) { return r.json(); }).then(function (resp) {
												var loopHtml = resp && (resp.loop || resp.t) ? (resp.loop || resp.t) : '';
												if (!loopHtml) { window.__mydInsertingIds.delete(id); return; }
												var dp = null;
												try { dp = new DOMParser().parseFromString(loopHtml, 'text/html'); } catch (e) { dp = document.createElement('div'); dp.innerHTML = loopHtml; }
												var found = null;
												try { found = dp.querySelector('.fdm-orders-items#' + CSS.escape(id)); } catch (_) { found = null; }
												if (!found) {
													var all = dp.querySelectorAll('.fdm-orders-items');
													for (var i = 0; i < all.length; i++) { if (String(all[i].id) === id) { found = all[i]; break; } }
												}
												if (found) {
													// Guard final: verifica novamente se o card surgiu no DOM enquanto fazia fetch
													if (document.getElementById(id)) {
														window.__mydInsertingIds.delete(id);
														console.log('[Orders Panel][frontend.min] Card #' + id + ' apareceu no DOM durante fetch — pulando (dedup)');
														return;
													}
													var st = found.getAttribute('data-order-status');
													var ns = normalizeStatus(st);
													var container = null;
													if (ns === 'new') container = document.querySelector('#myd-section-new .myd-orders-accordion-body');
													else if (ns === 'in-delivery') container = document.querySelector('#myd-section-in-delivery .myd-orders-accordion-body');
													else if (['confirmed', 'waiting'].indexOf(ns) !== -1) container = document.querySelector('#myd-section-production .myd-orders-accordion-body');
													else container = document.querySelector('#myd-section-done .myd-orders-accordion-body');
													if (!container) container = document.querySelector('.fdm-orders-loop');
													if (container) {
														try { container.insertBefore(found, container.firstElementChild); } catch (_) { try { container.appendChild(found); } catch (_) { } }
														try { found.classList.add('fdm-new-arrival'); setTimeout(function () { try { found.classList.remove('fdm-new-arrival'); } catch (_) { } }, 7000); } catch (_) { }
														try { if (window.MydRefreshOrderCounts && typeof window.MydRefreshOrderCounts === 'function') window.MydRefreshOrderCounts(); } catch (_) { }
													}
													window.__mydInsertingIds.delete(id);
													try { if (ns === 'new' && window.MydAlert && typeof window.MydAlert.add === 'function') window.MydAlert.add(id); } catch (_) { }
												} else {
													window.__mydInsertingIds.delete(id);
												}
												// Inserir detalhes completos se presentes
												try {
													var fullHtml = resp && resp.full ? resp.full : '';
													if (fullHtml) {
														var host = document.querySelector('.fdm-orders-full');
														if (host) {
															var parsedFull = new DOMParser().parseFromString(fullHtml, 'text/html');
															var fullEl = parsedFull.querySelector('#content-' + CSS.escape(id));
															if (fullEl && !document.getElementById('content-' + id)) { fullEl.style.display = 'none'; host.appendChild(fullEl); }
														}
													}
												} catch (_) { }
											}).catch(function (e) { window.__mydInsertingIds && window.__mydInsertingIds.delete(id); console.warn('[Orders Panel][frontend.min] fetchAndInsert failed', e); });
										}
									} catch (e) { window.__mydInsertingIds && window.__mydInsertingIds.delete(id); console.warn('[Orders Panel][frontend.min] fetchAndInsert error', e); }
								})();
								// set data-order-status
								try { item.setAttribute('data-order-status', status); } catch (e) { }
								// remove new highlight for terminal statuses
								try { if (['done', 'finished', 'canceled', 'refunded'].indexOf(status) !== -1) { item.classList.remove('fdm-new-unclicked'); item.removeAttribute('data-order-clicked'); item.style.removeProperty('background'); item.style.removeProperty('border'); } } catch (_) { }
								// move to target container
								try {
									function getTargetContainerByStatus(s) {
										s = normalizeStatus(s);
										var container = null;
										if (s === 'new') container = document.querySelector('#myd-section-new .myd-orders-accordion-body');
										else if (s === 'in-delivery') container = document.querySelector('#myd-section-in-delivery .myd-orders-accordion-body');
										else if (['confirmed', 'waiting'].indexOf(s) !== -1) container = document.querySelector('#myd-section-production .myd-orders-accordion-body');
										else container = document.querySelector('#myd-section-done .myd-orders-accordion-body');
										if (!container) container = document.querySelector('.fdm-orders-loop');
										return container;
									}
									var target = getTargetContainerByStatus(status);
									if (target && item.parentElement !== target) {
										try { item.parentElement && item.parentElement.removeChild(item); } catch (_) { }
										try { target.insertBefore(item, target.firstElementChild || null); } catch (e) { try { target.appendChild(item); } catch (_) { } }
										try { if (window.MydRefreshOrderCounts && typeof window.MydRefreshOrderCounts === 'function') window.MydRefreshOrderCounts(); } catch (_) { }
									}
								} catch (e) { }
								// auto-print handled by panel.php socket; do NOT call here (would flood prints)
								try { if (status === 'new' && window.MydAlert && typeof window.MydAlert.add === 'function') try { window.MydAlert.add(id); } catch (_) { } } catch (_) { }
								try { if ((status === 'confirmed' || status === 'canceled') && window.MydAlert && typeof window.MydAlert.removeFromSocket === 'function') try { window.MydAlert.removeFromSocket(id); } catch (_) { } } catch (_) { }
								// Play check sound when order reaches done/finished status
								try { if (status === 'done' || status === 'finished') { try { if (window.MydAudio && typeof window.MydAudio.playFinished === 'function') window.MydAudio.playFinished(); } catch (_) { } try { if (window.MydAlert && typeof window.MydAlert.removeFromSocket === 'function') window.MydAlert.removeFromSocket(id); } catch (_) { } } } catch (_) { }
							} catch (e) { console.error('[Orders Panel][frontend.min] UI mirror failed', e); }
						});
						socket.on('connect_error', function (err) { console.error('[Orders Panel][frontend.min] socket connect_error', err); });
						socket.on('disconnect', function (reason) { console.log('[Orders Panel][frontend.min] socket disconnected', reason); });
					} catch (e) { console.error('[Orders Panel][frontend.min] socket init failed', e); }
				} else {
					console.error('[Orders Panel][frontend.min] token fetch returned no token', data);
				}
			}).catch(function (e) { console.error('[Orders Panel][frontend.min] token fetch error', e); });
		} catch (e) { console.error('[Orders Panel][frontend.min] token request failed', e); }
	}

	document.addEventListener('DOMContentLoaded', function () {
		try {
			// Guard: se o panel.php já registrou o socket principal, este fallback não deve criar
			// uma segunda conexão independente (evita listeners duplicados de order.status).
			// O panel.php sinaliza sua presença definindo window._mydPanelSocketRegistered = true.
			if (window._mydPanelSocketRegistered) {
				console.log('[Orders Panel][frontend.min] panel.php socket já registrado — fallback ignorado');
				return;
			}
			// Use localized config when available (set in PHP via wp_localize_script)
			var cfg = window.MYD_ORDERS_PANEL || {};
			var pushUrl = cfg.push_url || (window.MYD_PUSH_SERVER_URL || '');
			var restBase = cfg.rest_base || '/wp-json/myd-delivery/v1/';
			if (!pushUrl) { console.warn('[Orders Panel][frontend.min] no pushUrl provided'); return; }
			ensureSocketIo(function () {
				if (typeof io === 'undefined') { console.error('[Orders Panel][frontend.min] io() not available after loading socket.io'); return; }
				fetchTokenAndConnect(pushUrl, restBase);
			});
		} catch (e) { console.error(e); }
	});
})();
